    assert_snapshot!(feyngen_str(&mut cli, "amp", "e- d > e- d | e- a d g ghg QED==2 [{3}] --symmetrize-left-right-states true --symmetric-left-right-polarizations true --numerator-grouping group_identical_graphs_up_to_scalar_rescaling",false)?,@"191 | -332/3+Group(102,1,1)+Group(103,-2/7,1)+Group(104,1,1)+Group(105,-7/2,1)+Group(162,1,1)+Group(163,7/2,1)+Group(164,1,1)+Group(165,2/7,1)+Group(172,1,1)+Group(173,1,1)+Group(315,1,1)+Group(316,-2/7,1) = -2183/21");

